Get-ChildItem -Path src -Recurse -Include *.ts,*.tsx | Where-Object { $_.FullName -notlike '*\__tests__\*' -and $_.FullName -notlike '*\node_modules\*' -and $_.Name -ne 'supabase.ts' } | ForEach-Object { [PSCustomObject]@{ Lines = (Get-Content $_.FullName | Measure-Object -Line).Lines; Path = $_.FullName } } | Where-Object Lines -gt 200 | Sort-Object -Property Lines -Descending | Format-Table -AutoSize